## ADR-004: Global Error Handling Strategy

**Status:** Proposed
**Supersedes:** Per-endpoint ad-hoc error handling (Phase 1 & 2 legacy)
**Must be consistent with:** ADR-001 (RS256 JWT Auth), ADR-002 (Sliding Window Rate Limiting), ADR-003 (RFC 9457 Error Format)

### Decision

Implement a **single global error handling middleware** as the terminal Express middleware. All application code throws typed error instances; the middleware is the sole serialiser of HTTP error responses. No endpoint may write its own error response directly.

---

## 1. Typed Error Class Hierarchy

```typescript
// src/errors/AppError.ts

/**
 * Base error class. All application errors extend this.
 * The global middleware inspects `instanceof` to route correctly.
 */
export abstract class AppError extends Error {
  abstract readonly statusCode: number;
  abstract readonly typeUri: string;   // Must be a registered URI in the error type registry
  abstract readonly title: string;

  constructor(
    public readonly detail: string,
    public readonly instance?: string,  // Set by middleware from req.path if omitted
    public readonly extensions: Record<string, unknown> = {}
  ) {
    super(detail);
    this.name = this.constructor.name;
    // Preserve prototype chain (TypeScript + transpilation safety)
    Object.setPrototypeOf(this, new.target.prototype);
  }
}

// ─── AUTH ERRORS (ADR-001) ────────────────────────────────────────────────────

/**
 * 401 Unauthorized — token absent, malformed, expired, or RS256 signature invalid.
 * ADR-001: RS256 validation failure maps here, NOT to 403.
 */
export class AuthenticationError extends AppError {
  readonly statusCode = 401;
  readonly typeUri = 'https://api.payments.example/errors/authentication-required';
  readonly title = 'Authentication Required';
}

/**
 * 403 Forbidden — token is valid and RS256-verified, but the token's
 * scope/permissions do not cover the requested resource or action.
 * ADR-001: This is the ONLY case for 403. A bad token is always 401.
 */
export class AuthorizationError extends AppError {
  readonly statusCode = 403;
  readonly typeUri = 'https://api.payments.example/errors/permission-denied';
  readonly title = 'Permission Denied';
}

// ─── RATE LIMIT ERRORS (ADR-002) ─────────────────────────────────────────────

/**
 * 429 Too Many Requests — sliding window limit exceeded.
 * ADR-002 + Constraint: Retry-After header is a contractual SLA obligation.
 * The retryAfterSeconds field is MANDATORY — middleware will throw if absent.
 */
export class RateLimitError extends AppError {
  readonly statusCode = 429;
  readonly typeUri = 'https://api.payments.example/errors/rate-limited';
  readonly title = 'Rate Limit Exceeded';

  constructor(
    detail: string,
    public readonly retryAfterSeconds: number,   // REQUIRED — drives Retry-After header
    public readonly limitHeader: number,          // X-RateLimit-Limit
    public readonly remainingHeader: number,      // X-RateLimit-Remaining (always 0 here)
    public readonly resetTimestamp: number,       // X-RateLimit-Reset (unix timestamp)
    instance?: string
  ) {
    super(detail, instance, {
      retry_after: retryAfterSeconds,             // RFC 9457 extension field mirrors header
    });
    if (retryAfterSeconds == null || retryAfterSeconds < 0) {
      // Hard guard: this error class cannot be constructed without a valid retry window
      throw new Error('RateLimitError requires a non-negative retryAfterSeconds');
    }
  }
}

// ─── VALIDATION ERRORS ───────────────────────────────────────────────────────

export interface FieldError {
  field: string;
  message: string;
}

export class ValidationError extends AppError {
  readonly statusCode = 422;
  readonly typeUri = 'https://api.payments.example/errors/validation-failed';
  readonly title = 'Validation Failed';

  constructor(
    detail: string,
    public readonly validationErrors: FieldError[],
    instance?: string
  ) {
    super(detail, instance, { validation_errors: validationErrors });
  }
}

// ─── PAYMENT DOMAIN ERRORS ───────────────────────────────────────────────────

export class InsufficientFundsError extends AppError {
  readonly statusCode = 402;
  readonly typeUri = 'https://api.payments.example/errors/insufficient-funds';
  readonly title = 'Insufficient Funds';
}

export class CardDeclinedError extends AppError {
  readonly statusCode = 402;
  readonly typeUri = 'https://api.payments.example/errors/card-declined';
  readonly title = 'Card Declined';
}

export class InvalidPaymentMethodError extends AppError {
  readonly statusCode = 422;
  readonly typeUri = 'https://api.payments.example/errors/invalid-payment-method';
  readonly title = 'Invalid Payment Method';
}

export class IdempotencyConflictError extends AppError {
  readonly statusCode = 409;
  readonly typeUri = 'https://api.payments.example/errors/idempotency-conflict';
  readonly title = 'Idempotency Key Conflict';
}

// ─── SUBSCRIPTION ERRORS (⚠ NEW — registry gap identified) ──────────────────
// NOTE: These types are NOT YET in the error type registry.
// They must be registered before deployment. See open question in checkpoint.

export class SubscriptionNotFoundError extends AppError {
  readonly statusCode = 404;
  readonly typeUri = 'https://api.payments.example/errors/subscription-not-found';
  readonly title = 'Subscription Not Found';
}

export class SubscriptionPaymentFailedError extends AppError {
  readonly statusCode = 402;
  readonly typeUri = 'https://api.payments.example/errors/subscription-payment-failed';
  readonly title = 'Subscription Payment Failed';
}
