## 2. Global Error Middleware

```typescript
// src/middleware/errorHandler.ts
import { Request, Response, NextFunction } from 'express';
import { AppError, RateLimitError, AuthenticationError } from '../errors/AppError';
import { logger } from '../lib/logger';   // Structured logger (Winston/Pino)
import { generateTraceId } from '../lib/tracing';

/**
 * GLOBAL ERROR HANDLER — must be registered as the LAST middleware in app.ts.
 *
 * Satisfies:
 *   - ADR-003: All responses use RFC 9457 Problem Details (application/problem+json)
 *   - ADR-002: 429 responses always include Retry-After + X-RateLimit-* headers
 *   - ADR-001: 401 vs 403 distinction is enforced by error class, not here
 *   - Constraint (high): RFC 9457 format — no custom formats permitted
 *   - Constraint (high): Retry-After header — contractual SLA obligation
 *   - PCI-DSS Req 3: No cardholder data in responses
 *   - PCI-DSS Req 6: No stack traces in production responses
 */
export function errorHandler(
  err: Error,
  req: Request,
  res: Response,
  _next: NextFunction   // Must have 4 params for Express to treat as error handler
): void {

  // ── 1. Resolve trace ID ──────────────────────────────────────────────────
  // Prefer upstream propagated ID (e.g. from OpenTelemetry span), else generate.
  const traceId: string =
    (req.headers['x-trace-id'] as string) ||
    (req as any).traceId ||
    generateTraceId();

  // ── 2. Classify the error ────────────────────────────────────────────────
  const isAppError = err instanceof AppError;
  const statusCode = isAppError ? (err as AppError).statusCode : 500;

  // ── 3. Log server-side (BEFORE sanitising the response) ─────────────────
  // PCI-DSS: log the full error for debugging, but NEVER send it to the client.
  // PCI-DSS Req 10: log timestamp, user, action, resource, result.
  const logPayload = {
    traceId,
    statusCode,
    errorName: err.name,
    errorMessage: err.message,
    // Stack trace logged server-side only — never sent to client
    stack: process.env.NODE_ENV !== 'production' ? err.stack : '[suppressed in production]',
    method: req.method,
    path: req.path,
    userId: (req as any).user?.sub ?? 'anonymous',
    apiKey: (req as any).apiKey ? '[present]' : '[absent]',  // Never log the key itself
  };

  if (statusCode >= 500) {
    logger.error('Unhandled server error', logPayload);
  } else if (statusCode === 429) {
    logger.warn('Rate limit exceeded', logPayload);
  } else {
    logger.info('Client error', logPayload);
  }

  // ── 4. Build RFC 9457 Problem Details body ───────────────────────────────
  // Constraint (high): ALL error responses MUST use this format. No exceptions.
  const problemDetails: Record<string, unknown> = {
    type: isAppError
      ? (err as AppError).typeUri
      : 'https://api.payments.example/errors/internal-server-error',
    title: isAppError
      ? (err as AppError).title
      : 'Internal Server Error',
    status: statusCode,
    // PCI-DSS: detail must NEVER contain card numbers, CVVs, or raw cardholder data.
    // For 500s, use a generic message — never expose internal details.
    detail: isAppError
      ? sanitiseDetail(err.message)
      : 'An unexpected error occurred. Please try again or contact support.',
    instance: isAppError && (err as AppError).instance
      ? (err as AppError).instance
      : req.path,
    trace_id: traceId,   // Required on all errors — fixes Phase 2 gap (5/8 endpoints missing)
    // Spread any typed extension fields (validation_errors, retry_after, etc.)
    ...(isAppError ? (err as AppError).extensions : {}),
  };

  // ── 5. Set response headers ──────────────────────────────────────────────
  res.setHeader('Content-Type', 'application/problem+json');

  // ADR-002 + Constraint (high): Rate limit headers MUST be present on 429.
  // This is a contractual SLA obligation per partner integration agreement 2025-Q3.
  if (err instanceof RateLimitError) {
    const rl = err as RateLimitError;

    // Contractually required header — constraint severity: HIGH
    res.setHeader('Retry-After', String(rl.retryAfterSeconds));

    // Full X-RateLimit suite (ADR-002)
    res.setHeader('X-RateLimit-Limit', String(rl.limitHeader));
    res.setHeader('X-RateLimit-Remaining', '0');   // Always 0 when limit is exceeded
    res.setHeader('X-RateLimit-Reset', String(rl.resetTimestamp));
  }

  // WWW-Authenticate required by RFC 9110 for 401 responses
  if (err instanceof AuthenticationError) {
    res.setHeader('WWW-Authenticate', 'Bearer realm="payments-api"');
  }

  // ── 6. Send response ─────────────────────────────────────────────────────
  res.status(statusCode).json(problemDetails);
}

/**
 * Sanitise error detail strings before sending to clients.
 * Strips anything that looks like cardholder data, internal paths, or secrets.
 * PCI-DSS Requirement 3.
 */
function sanitiseDetail(detail: string): string {
  return detail
    // Remove anything resembling a card number (13-19 digits)
    .replace(/\b\d{13,19}\b/g, '[REDACTED]')
    // Remove file system paths
    .replace(/\/[a-z0-9_\-/.]+\.(ts|js|json)/gi, '[path]')
    // Remove anything that looks like a secret key
    .replace(/\b(sk_|pk_|rk_)[a-z0-9_]+/gi, '[REDACTED]');
}
```

