## 3. Auth Middleware — Enforcing the 401 / 403 Distinction (ADR-001)

```typescript
// src/middleware/authenticate.ts
import { Request, Response, NextFunction } from 'express';
import { AuthenticationError, AuthorizationError } from '../errors/AppError';
import { verifyRS256Token } from '../lib/jwt';   // Uses JWKS endpoint, NOT shared secret

/**
 * Authentication middleware.
 *
 * ADR-001 + Constraint (CRITICAL): Tokens MUST be RS256-signed.
 * HS256 tokens are REJECTED — this is a compliance requirement from SEC-2025-041.
 *
 * 401 vs 403 decision tree (ADR-001):
 *   - No Authorization header           → 401 (authentication-required)
 *   - Malformed Bearer token            → 401 (authentication-required)
 *   - Token signature invalid           → 401 (authentication-required)
 *   - Token expired (exp claim)         → 401 (authentication-required)
 *   - Token algorithm is not RS256      → 401 (authentication-required) [SEC-2025-041]
 *   - Token valid BUT wrong scope       → 403 (permission-denied)
 *   - Token valid BUT wrong tenant      → 403 (permission-denied)
 */
export function authenticate(req: Request, _res: Response, next: NextFunction): void {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    // No token at all → 401
    return next(new AuthenticationError(
      'This endpoint requires a Bearer token. Please authenticate and retry.',
      req.path
    ));
  }

  const token = authHeader.slice(7);
